"use strict";parserFactory.register("alphapolis.co.jp",()=>new AlphapolisParser);class AlphapolisParser extends Parser{constructor(){super(),this.minimumThrottle=15e3}async getChapterUrls(e){let t=e.querySelector("div.episodes");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("div#novelBody")}extractTitleImpl(e){return e.querySelector("div.content-main .title")}extractAuthor(e){let t=e.querySelector("div.author a");return null===t?super.extractAuthor(e):t.textContent}extractLanguage(){return"jp"}findChapterTitle(e){return e.querySelector("h2.episode-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.content-info .cover")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.abstract")]}}